sql:
SELECT mean 
FROM interval_statistics 
WHERE interval_id = 1;

SELECT set_name
FROM interval_sets
WHERE set_id = 1;

SELECT COUNT(interval_id) AS active_intervals
  FROM intervals
  WHERE is_active = 1;

SELECT name
FROM interval_types
WHERE is_discrete = 1 AND is_computable = 1;

SELECT interval_id
FROM intervals
WHERE is_active = 1;

SELECT COUNT(*) AS action_count
FROM interval_logs
WHERE user_id = 1;

SELECT user_id, action
FROM interval_logs
WHERE action = 'created';

SELECT COUNT(interval_type_id) AS computable_interval_count
FROM interval_types
WHERE is_computable = 1;

external_knowledge:
; The term 'active intervals' refers to intervals with is_active = 1; 
; 'mean greater than 0.5' means the average of interval values is above the midpoint of the 0-1 range;
; 'condition ID equal to 0' implies a default or unspecified condition.
